/** Typed guard — runtime validates StdGenericAppNoteOrbitalParams keys. */
export function isStdGenericAppNoteOrbitalParams(p: object): p is StdGenericAppNoteOrbitalParams {
  type _OverrideRecord = NonNullable<StdGenericAppNoteOrbitalParams['traitOverrides']>;
  const obj = p as { traitOverrides?: _OverrideRecord };
  if (obj.traitOverrides !== undefined) {
    if (typeof obj.traitOverrides !== "object" || obj.traitOverrides === null) return false;
    const allowed: readonly string[] = StdGenericAppNoteOrbitalManifest.traitNames;
    for (const k of Object.keys(obj.traitOverrides)) {
      if (!allowed.includes(k)) return false;
    }
  }
  return true;
}

/**
 * Bundled params for std-generic-app — one optional entry per orbital.
 * Each entry maps to its per-orbital factory above.
 */
export interface StdGenericAppParams {
  Contact?: StdGenericAppContactOrbitalParams;
  Item?: StdGenericAppItemOrbitalParams;
  Activity?: StdGenericAppActivityOrbitalParams;
  Task?: StdGenericAppTaskOrbitalParams;
  Calendar?: StdGenericAppCalendarOrbitalParams;
  Widget?: StdGenericAppWidgetOrbitalParams;
  Feed?: StdGenericAppFeedOrbitalParams;
  Note?: StdGenericAppNoteOrbitalParams;
}

/** Whole-organism descriptor (8 orbitals). Composes per-orbital factories. */
export function stdGenericApp(params: StdGenericAppParams = {}): OrbitalDefinition[] {
  return [
    stdGenericAppContactOrbital(params.Contact ?? {}),
    stdGenericAppItemOrbital(params.Item ?? {}),
    stdGenericAppActivityOrbital(params.Activity ?? {}),
    stdGenericAppTaskOrbital(params.Task ?? {}),
    stdGenericAppCalendarOrbital(params.Calendar ?? {}),
    stdGenericAppWidgetOrbital(params.Widget ?? {}),
    stdGenericAppFeedOrbital(params.Feed ?? {}),
    stdGenericAppNoteOrbital(params.Note ?? {}),
  ];
}
